mapper.select:
select id, counter_type as counterType, tenant_id as tenantId, zs_customer_id as zsCustomerId,
       warehouse_id as warehouseId, high_low_flag as highLowFlag, seed_value as seedValue
from scm_barcode_seed
where counter_type = #{counterType}
  and tenant_id = #{tenantId}
  and zs_customer_id = #{zsCustomerId}
  and warehouse_id = #{warehouseId}
  and high_low_flag = #{highLowFlag}
for update

mapper.update:
update scm_barcode_seed
set seed_value = #{newValue}, update_time = now()
where id = #{id}

mapper.insert:
insert into scm_barcode_seed (id, counter_type, tenant_id, zs_customer_id, warehouse_id, high_low_flag, seed_value, create_time)
select #{id}, 'Z', #{tenantId}, #{zsCustomerId}, #{warehouseId}, #{highLowFlag}, 0, now()
from dual
where not exists (
    select 1 from scm_barcode_seed s
    where s.counter_type = 'Z' and s.tenant_id = #{tenantId} and s.zs_customer_id = #{zsCustomerId}
      and s.warehouse_id = #{warehouseId} and s.high_low_flag = #{highLowFlag}
)
